var options = {
  series: [
    {
      name: 'Net Margin',
      data: [
        8.2, 12.5, 6.1, -3.4, -9.8, -14.2, -6.5, 2.1, 9.4, 15.8, 11.2, -4.6,
      ],
    },
  ],
  chart: {
    type: 'bar',
    height: 350,
  },
  title: {
    text: 'Monthly Net Profit Margin',
    align: 'left',
  },
  plotOptions: {
    bar: {
      colors: {
        ranges: [
          {
            from: -30,
            to: -8,
            color: '#F15B46',
          },
          {
            from: -8,
            to: 0,
            color: '#FEB019',
          },
        ],
      },
      columnWidth: '70%',
      dataLabels: {
        orientation: 'vertical',
        position: 'top', // top, center, bottom
      },
    },
  },
  dataLabels: {
    enabled: true,
    offsetY: 2,
    formatter: function (val) {
      return val + '%'
    },
    style: {
      fontSize: '12px',
      colors: ['#000000'],
    },
  },
  yaxis: {
    title: {
      text: 'Net Margin',
    },
    labels: {
      formatter: function (y) {
        return y.toFixed(0) + '%'
      },
    },
  },
  xaxis: {
    type: 'category',
    categories: [
      'Jan',
      'Feb',
      'Mar',
      'Apr',
      'May',
      'Jun',
      'Jul',
      'Aug',
      'Sep',
      'Oct',
      'Nov',
      'Dec',
    ],
  },
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()
